{
  "scripts": {
    "prebuild":   "node scripts/check-env.js",   // runs before "build"
    "build":      "ng build",
    "postbuild":  "node scripts/copy-assets.js", // runs after "build"

    "pretest":    "ng lint",                     // lint before tests
    "test":       "ng test",

    "start":      "ng serve",
    "start:prod": "ng serve --configuration production",

    "analyze":    "ng build --stats-json && npx webpack-bundle-analyzer dist/stats.json"
  }
}

# .npmrc (committed to the project root)
registry=https://registry.npmjs.org/
@myorg:registry=https://npm.pkg.github.com/
//npm.pkg.github.com/:_authToken=${GITHUB_TOKEN}

# Verify effective config
npm config list
npm config get registry

// scripts/check-env.js
const required = ['API_URL', 'AUTH_DOMAIN'];
const missing  = required.filter(k => !process.env[k]);
if (missing.length) {
  console.error(`Missing env vars: ${missing.join(', ')}`);
  process.exit(1);
}
console.log('Environment OK.');

npm install --save-dev cross-env

{
  "scripts": {
    "build:staging": "cross-env NODE_ENV=staging API_URL=https://staging.api.com ng build",
    "test:ci":       "cross-env CI=true ng test --no-watch --no-progress"
  }
}
